namespace XrmToolSuite.EnvironmentComparisonSuite
{
    // The UI is built entirely in code (see BuildUi() in the main partial class), mirroring the
    // Deployment Risk Analyzer. This file only carries the designer-required Dispose plumbing.
    partial class EnvironmentComparisonSuiteControl
    {
        private System.ComponentModel.IContainer components = null;

        protected override void Dispose(bool disposing)
        {
            if (disposing && components != null) components.Dispose();
            base.Dispose(disposing);
        }
    }
}
